  "type": "CODE_BUILDER",
  "lessonText": "In this lesson, you'll create basic interactive elements in Python for your game.",
  "data": {
    "codeBuilder": {
      "avatarInstruction": "Fill in the blanks to create an interactive avatar movement.",
      "lines": [
        {
          "content": "def move_avatar(direction):\n    if direction == 'up':\n        avatar_y += ___\n    elif direction == 'down':\n        avatar_y -= ___\n    elif direction == 'left':\n        avatar_x -= ___\n    elif direction == 'right':\n        avatar_x += ___",
          "correctValue": "10"
        },
        {
          "content": "def jump_avatar():\n    avatar_y += ___",
          "correctValue": "20"
        },
        {
          "content": "def reset_avatar():\n    avatar_x = ___\n    avatar_y = ___",
          "correctValue": "0"
        },
        {
          "content": "def print_position():\n    print('Avatar position:', avatar_x, ___)",
          "correctValue": "avatar_y"
        }
      ],
      "options": [
        "10",
        "20",
        "0",
        "avatar_y"
      ]
    }
  }
